python3 -c "
import openpyxl
wb = openpyxl.load_workbook('input.xlsx')
print('Sheets:', wb.sheetnames)
for name in wb.sheetnames:
    ws = wb[name]
    print(f'\n--- {name} (rows={ws.max_row}, cols={ws.max_column}) ---')
    for row in ws.iter_rows(min_row=1, max_row=min(ws.max_row, 20), values_only=False):
        for cell in row:
            if cell.value is not None:
                print(f'  {cell.coordinate}: value={cell.value!r}, number_format={cell.number_format}')
"

